module RefModule(
    input wire clk,
    input wire enable,
    input wire reset,
    input wire load,
    input wire [3:0] data,
    output reg [3:0] count
    );

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
    if (reset)
        count <= 4'b0000;
    else if (load)
        count <= data;
    else if (enable)
        count <= count + 1;
end

endmodule
